node - <<'NODE'
const records = [
  {id:'R1', metric1:764, metric2:90.9, metric3:2, metric4:9.56},
  {id:'R2', metric1:11, metric2:75.99, metric3:114, metric4:8.66},
  {id:'R3', metric1:375, metric2:34.72, metric3:80, metric4:4.53},
  {id:'R4', metric1:335, metric2:13.45, metric3:100, metric4:1.84},
];
function pri(r){return r.metric1*r.metric2 - 0.6*r.metric3 + r.metric4;}
for (const pct of [-0.05, 0.05]) {
  const out = records.map(r => ({id:r.id, p: pri({
    metric1:r.metric1*(1+pct),
    metric2:r.metric2*(1+pct),
    metric3:r.metric3*(1+pct),
    metric4:r.metric4*(1+pct),
  })})).sort((a,b)=>b.p-a.p);
  console.log('pct', pct, JSON.stringify(out));
}
